<template>
    <div class="info-page">
        <div class="page-title">系统概览</div>

        <el-row :gutter="20" class="mgb20">
            <el-col :span="6">
                <el-card class="stat-card">
                    <div class="stat-label">用户总数</div>
                    <div class="stat-value">{{ consumerCount }}</div>
                    <div class="stat-sub">累计注册用户</div>
                </el-card>
            </el-col>
            <el-col :span="6">
                <el-card class="stat-card">
                    <div class="stat-label">歌曲总数</div>
                    <div class="stat-value">{{ songCount }}</div>
                    <div class="stat-sub">已收录歌曲</div>
                </el-card>
            </el-col>
            <el-col :span="6">
                <el-card class="stat-card">
                    <div class="stat-label">歌手总数</div>
                    <div class="stat-value">{{ singerCount }}</div>
                    <div class="stat-sub">入库歌手</div>
                </el-card>
            </el-col>
            <el-col :span="6">
                <el-card class="stat-card">
                    <div class="stat-label">歌单总数</div>
                    <div class="stat-value">{{ songListCount }}</div>
                    <div class="stat-sub">已创建歌单</div>
                </el-card>
            </el-col>
        </el-row>

        <el-row :gutter="20" class="mgb20">
            <el-col :span="24">
                <el-card class="chart-card">
                    <div class="section-title">按天新增用户</div>
                    <ve-line
                        :data="dailyUserChart"
                        :settings="lineSettings"
                        :extend="lineExtend"
                    ></ve-line>
                </el-card>
            </el-col>
        </el-row>

        <el-row :gutter="20" class="mgb20">
            <el-col :span="12">
                <el-card class="table-card">
                    <div class="section-title">热门歌曲榜</div>
                    <el-table :data="hotSongs" size="small" height="320">
                        <el-table-column
                            type="index"
                            label="#"
                            width="60"
                        ></el-table-column>
                        <el-table-column
                            prop="name"
                            label="歌曲"
                        ></el-table-column>
                        <el-table-column
                            prop="playCount"
                            label="播放量"
                            width="110"
                            :formatter="fmtNumber"
                        ></el-table-column>
                        <el-table-column
                            prop="collectCount"
                            label="收藏量"
                            width="110"
                            :formatter="fmtNumber"
                        ></el-table-column>
                    </el-table>
                </el-card>
            </el-col>
            <el-col :span="12">
                <el-card class="table-card">
                    <div class="section-title">热门歌手榜</div>
                    <el-table :data="hotSingers" size="small" height="320">
                        <el-table-column
                            type="index"
                            label="#"
                            width="60"
                        ></el-table-column>
                        <el-table-column
                            prop="name"
                            label="歌手"
                        ></el-table-column>
                        <el-table-column
                            prop="playCount"
                            label="播放量"
                            width="110"
                            :formatter="fmtNumber"
                        ></el-table-column>
                        <el-table-column
                            prop="collectCount"
                            label="收藏量"
                            width="110"
                            :formatter="fmtNumber"
                        ></el-table-column>
                    </el-table>
                </el-card>
            </el-col>
        </el-row>

        <el-row :gutter="20" class="mgb20">
            <el-col :span="12">
                <el-card class="chart-card">
                    <div class="section-title">播放量排行</div>
                    <ve-histogram
                        :data="playRankChart"
                        :settings="barSettings"
                    ></ve-histogram>
                </el-card>
            </el-col>
            <el-col :span="12">
                <el-card class="chart-card">
                    <div class="section-title">收藏量排行</div>
                    <ve-histogram
                        :data="collectRankChart"
                        :settings="barSettings"
                    ></ve-histogram>
                </el-card>
            </el-col>
        </el-row>
    </div>
</template>

<script>
import { mixin } from "../mixins/index";
import {
    getAllConsumer,
    allSong,
    getAllSinger,
    getAllSongList,
    getHotSongs,
    getHotSingers,
    getPlayRank,
    getCollectRank,
    getDailyNewUsers
} from "../api/index";

export default {
    mixins: [mixin],
    data() {
        return {
            consumerCount: 0,
            songCount: 0,
            singerCount: 0,
            songListCount: 0,
            hotSongs: [],
            hotSingers: [],
            playRank: [],
            collectRank: [],
            dailyUsers: [],
            dailyUserChart: {
                columns: ["日期", "新增用户"],
                rows: []
            },
            playRankChart: {
                columns: ["歌曲", "播放量"],
                rows: []
            },
            collectRankChart: {
                columns: ["歌曲", "收藏量"],
                rows: []
            },
            lineSettings: {
                area: true
            },
            lineExtend: {
                grid: { left: 40, right: 20, top: 20, bottom: 30 }
            },
            barSettings: {
                labelMap: {}
            }
        };
    },
    mounted() {
        this.loadBaseCounts();
        this.fetchAll();
    },
    methods: {
        unwrap(res) {
            if (res && Object.prototype.hasOwnProperty.call(res, "data")) {
                return res.data;
            }
            return res;
        },
        fmtNumber(row, column, value) {
            if (value === null || value === undefined || value === "") return 0;
            return value;
        },
        async loadBaseCounts() {
            try {
                const list = await getAllConsumer();
                this.consumerCount = Array.isArray(list) ? list.length : 0;
            } catch (e) {
                this.consumerCount = 0;
            }
            try {
                const list = await allSong();
                this.songCount = Array.isArray(list) ? list.length : 0;
            } catch (e) {
                this.songCount = 0;
            }
            try {
                const list = await getAllSinger();
                this.singerCount = Array.isArray(list) ? list.length : 0;
            } catch (e) {
                this.singerCount = 0;
            }
            try {
                const list = await getAllSongList();
                this.songListCount = Array.isArray(list) ? list.length : 0;
            } catch (e) {
                this.songListCount = 0;
            }
        },
        async fetchAll() {
            await Promise.all([
                this.fetchHotSongs(),
                this.fetchHotSingers(),
                this.fetchPlayRank(),
                this.fetchCollectRank(),
                this.fetchDailyUsers()
            ]);
        },
        async fetchHotSongs() {
            try {
                const res = await getHotSongs(10);
                const list = this.unwrap(res);
                this.hotSongs = Array.isArray(list) ? list : [];
            } catch (e) {
                this.hotSongs = [];
            }
        },
        async fetchHotSingers() {
            try {
                const res = await getHotSingers(10);
                const list = this.unwrap(res);
                this.hotSingers = Array.isArray(list) ? list : [];
            } catch (e) {
                this.hotSingers = [];
            }
        },
        async fetchPlayRank() {
            try {
                const res = await getPlayRank(10);
                const list = this.unwrap(res);
                this.playRank = Array.isArray(list) ? list : [];
                this.playRankChart.rows = this.playRank.map((item) => ({
                    歌曲: item.name || "",
                    播放量: item.playCount || 0
                }));
            } catch (e) {
                this.playRank = [];
                this.playRankChart.rows = [];
            }
        },
        async fetchCollectRank() {
            try {
                const res = await getCollectRank(10);
                const list = this.unwrap(res);
                this.collectRank = Array.isArray(list) ? list : [];
                this.collectRankChart.rows = this.collectRank.map((item) => ({
                    歌曲: item.name || "",
                    收藏量: item.collectCount || 0
                }));
            } catch (e) {
                this.collectRank = [];
                this.collectRankChart.rows = [];
            }
        },
        async fetchDailyUsers() {
            try {
                const res = await getDailyNewUsers(14);
                const list = this.unwrap(res);
                this.dailyUsers = Array.isArray(list) ? list : [];
                this.dailyUserChart.rows = this.dailyUsers.map((item) => ({
                    日期: item.day || "",
                    新增用户: item.count || 0
                }));
            } catch (e) {
                this.dailyUsers = [];
                this.dailyUserChart.rows = [];
            }
        },
    }
};
</script>

<style scoped>
.info-page {
    padding: 20px;
}

.page-title {
    font-size: 22px;
    font-weight: 700;
    margin-bottom: 16px;
    color: #0f172a;
}

.section-title {
    font-size: 18px;
    font-weight: 700;
    margin-bottom: 12px;
    color: #0f172a;
}

.stat-card {
    min-height: 120px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
}

.stat-label {
    font-size: 14px;
    color: #64748b;
}

.stat-value {
    font-size: 30px;
    font-weight: 700;
    color: #111827;
    margin: 6px 0;
}

.stat-sub {
    font-size: 12px;
    color: #94a3b8;
}

.chart-card,
.table-card {
    min-height: 360px;
}
</style>



